const period = $('Check if monthly digest is due').first().json;
const stats = $('Query month stats').first().json;
const weeks = $('Query weekly breakdown').all().map(i => i.json);
const categories = $('Query category breakdown').all().map(i => i.json);
const failures = $('Query open failures').all().map(i => i.json);

const fmtINR = n => Number(n).toLocaleString('en-IN', { style: 'currency', currency: 'INR' });
const monthLabel = new Date(period.period_start + 'T00:00:00+05:30')
  .toLocaleDateString('en-IN', { month: 'long', year: 'numeric' });
const fmtDate = d => new Date(d + 'T00:00:00+05:30')
  .toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });

const weekRows = weeks.length === 0
  ? '<tr><td colspan="4" style="color:#999">No transactions this month</td></tr>'
  : weeks.map(w =>
      `<tr><td>${fmtDate(w.week_start)} – ${fmtDate(w.week_end)}</td><td>${w.transactions}</td><td>${fmtINR(w.spent)}</td><td>${fmtINR(w.received)}</td></tr>`
    ).join('');

const catRows = categories.length === 0
  ? '<tr><td colspan="3" style="color:#999">No spending data</td></tr>'
  : categories.map(c =>
      `<tr><td>${c.category}</td><td>${c.transactions}</td><td>${fmtINR(c.total)}</td></tr>`
    ).join('');

let failureRows = failures.length === 0
  ? '<tr><td colspan="4" style="color:green">None — all clear</td></tr>'
  : failures.map(f =>
      `<tr><td>${f.id}</td><td>${f.stage}</td><td>${f.subject || '—'}</td><td>${f.error_message?.substring(0, 80) || '—'}</td></tr>`
    ).join('');

const html = `
<html><body style="font-family: sans-serif; color: #222; max-width: 700px; margin: auto">
<h2>Finance pipeline — monthly digest</h2>
<p style="color: #666">${monthLabel}</p>

<h3>Month summary</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>Metric</th><th>Value</th></tr>
  <tr><td>Emails ingested</td><td>${stats.raw_ingested}</td></tr>
  <tr><td>Transactions written</td><td>${stats.written_to_ebk}</td></tr>
  <tr><td>Deduplicated (dropped)</td><td>${stats.deduplicated}</td></tr>
  <tr><td>GroqCloud fallback calls</td><td>${stats.groq_calls}</td></tr>
  <tr><td>Open failures</td><td style="color:${stats.open_failures > 0 ? 'red' : 'green'}">${stats.open_failures}</td></tr>
  <tr><td>Total spent</td><td><strong>${fmtINR(stats.month_spend)}</strong></td></tr>
  <tr><td>Total received</td><td>${fmtINR(stats.month_received)}</td></tr>
</table>

<h3>Weekly breakdown</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>Week</th><th>Transactions</th><th>Spent</th><th>Received</th></tr>
  ${weekRows}
</table>

<h3>Spending by category</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>Category</th><th>Transactions</th><th>Total</th></tr>
  ${catRows}
</table>

<h3>Open failures</h3>
<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse; width:100%">
  <tr style="background:#f0f0f0"><th>ID</th><th>Stage</th><th>Email subject</th><th>Error</th></tr>
  ${failureRows}
</table>

<p style="font-size:12px;color:#999">To mark a failure resolved: <code>UPDATE failed_events SET resolved=TRUE WHERE id=&lt;id&gt;;</code><br>
To promote a Groq pattern to regex: see RUNBOOK.md</p>
</body></html>
`;

return [{ json: { subject: `Finance monthly digest — ${monthLabel}`, html, period_end: period.period_end } }];
